const results = $input.first().json;
const leads = Array.isArray(results) ? results : [results];
const validLeads = leads.filter(lead => lead && lead.id);

if (validLeads.length === 0) {
  return [];
}

const baseUrl = $env.SUPABASE_URL;
const key = $env.SUPABASE_SERVICE_ROLE_KEY;
const headers = {
  apikey: key,
  Authorization: `Bearer ${key}`,
  'Content-Type': 'application/json',
  Prefer: 'return=minimal'
};

const STEP_TO_TRIGGER = {
  0: 'first_contact',
  1: 'follow_up_day3',
  2: 'follow_up_day7',
  3: 'follow_up_day14',
  4: 'follow_up_day30'
};

function toDate(value) {
  if (!value) return null;
  const parsed = new Date(value);
  return Number.isNaN(parsed.getTime()) ? null : parsed;
}

function getMinutesInTimeZone(date, timeZone) {
  const parts = new Intl.DateTimeFormat('en-CA', {
    hour: '2-digit',
    minute: '2-digit',
    hour12: false,
    timeZone: timeZone || 'America/Toronto'
  }).formatToParts(date);

  const hours = parseInt(parts.find(part => part.type === 'hour')?.value || '0', 10);
  const minutes = parseInt(parts.find(part => part.type === 'minute')?.value || '0', 10);
  return hours * 60 + minutes;
}

function isWorking(rep, date) {
  if (!rep?.active) return false;
  const start = Number(rep.shift_start_minutes);
  const end = Number(rep.shift_end_minutes);
  if (!Number.isFinite(start) || !Number.isFinite(end) || start === end) return true;

  const nowMinutes = getMinutesInTimeZone(date, rep.shift_timezone || 'America/Toronto');
  if (start < end) {
    return nowMinutes >= start && nowMinutes < end;
  }

  return nowMinutes >= start || nowMinutes < end;
}

function leadRepliedSinceAssignment(lead) {
  const assignedAt = toDate(lead.assigned_at);
  const lastReplyAt = toDate(lead.last_reply_at);
  if (!assignedAt || !lastReplyAt) return false;
  return lastReplyAt.getTime() >= assignedAt.getTime();
}

async function patchLead(leadId, payload) {
  await fetch(`${baseUrl}/rest/v1/leads?id=eq.${leadId}`, {
    method: 'PATCH',
    headers,
    body: JSON.stringify(payload)
  });
}

async function fetchWorkingReps(excludeId, now) {
  const response = await fetch(`${baseUrl}/rest/v1/profiles?active=eq.true&select=id,name,rr_order,active,shift_start_minutes,shift_end_minutes,shift_timezone`, { headers: { apikey: key, Authorization: `Bearer ${key}` } });
  const raw = await response.json();
  const reps = (Array.isArray(raw) ? raw : [])
    .filter(rep => isWorking(rep, now))
    .sort((a, b) => {
      const orderDiff = (a.rr_order ?? 0) - (b.rr_order ?? 0);
      if (orderDiff !== 0) return orderDiff;
      return (a.name || '').localeCompare(b.name || '');
    });

  if (reps.length <= 1) return reps;
  return reps.filter(rep => rep.id !== excludeId);
}

async function nextRep(excludeId, now) {
  const reps = await fetchWorkingReps(excludeId, now);
  if (reps.length === 0) return null;

  const settingsResponse = await fetch(`${baseUrl}/rest/v1/settings?key=eq.rr_index&select=value`, { headers: { apikey: key, Authorization: `Bearer ${key}` } });
  const settings = await settingsResponse.json();
  const rawIndex = settings[0]?.value ?? 0;
  const currentIndex = typeof rawIndex === 'number' ? rawIndex : parseInt(String(rawIndex).replace(/[^\d-]/g, ''), 10) || 0;
  const idx = ((currentIndex % reps.length) + reps.length) % reps.length;
  const rep = reps[idx];
  const nextIndex = (idx + 1) % reps.length;

  await fetch(`${baseUrl}/rest/v1/settings?key=eq.rr_index`, {
    method: 'PATCH',
    headers,
    body: JSON.stringify({ value: nextIndex })
  });

  return rep;
}

const now = new Date();
const fourHoursMs = 4 * 60 * 60 * 1000;
const threeDaysMs = 3 * 24 * 60 * 60 * 1000;
const actions = [];

for (const lead of validLeads) {
  const assignedAt = toDate(lead.assigned_at);
  const nextFollowUp = toDate(lead.next_follow_up);
  const repResponded = Boolean(lead.rep_response_at);

  if (assignedAt && !repResponded) {
    const ageMs = now.getTime() - assignedAt.getTime();

    if (ageMs >= threeDaysMs && !leadRepliedSinceAssignment(lead)) {
      const reassignedRep = await nextRep(lead.assigned_to, now);
      await patchLead(lead.id, {
        assigned_to: reassignedRep?.id ?? null,
        assigned_at: now.toISOString(),
        rep_response_at: null,
        autopilot_active: true,
        sequence_step: 0,
        stage: 'new',
        next_follow_up: null
      });

      actions.push({ json: { id: lead.id, trigger_type: 'first_contact', _action: 'send' } });
      continue;
    }

    if (ageMs >= fourHoursMs && !lead.autopilot_active) {
      await patchLead(lead.id, { autopilot_active: true });
      actions.push({ json: { id: lead.id, trigger_type: 'first_contact', _action: 'send' } });
      continue;
    }
  }

  if (!lead.autopilot_active || !nextFollowUp || nextFollowUp.getTime() > now.getTime()) {
    continue;
  }

  const step = lead.sequence_step || 0;
  if (step > 4) {
    await patchLead(lead.id, { stage: 'closed', next_follow_up: null, autopilot_active: false });
    continue;
  }

  actions.push({ json: { id: lead.id, trigger_type: STEP_TO_TRIGGER[step] || 'follow_up_day30', _action: 'send' } });
}

return actions;
